import type { CSSProperties, MouseEvent, ReactNode } from 'react'
import { forwardRef, useEffect, useRef } from 'react'
import type { Ref } from 'react'
import { Button as TuiButton } from '@tangible/ui'
import type { ButtonProps as TuiButtonProps } from '@tangible/ui'

import { isDev } from '../../../utils/is-dev'
import { triggerEvent } from '../../../events'
import LegacyButton from './LegacyButton'

type MappedLayout =
  | 'primary'
  | 'action'
  | 'danger'
  | 'text-action'
  | 'text-primary'
  | 'text-danger'

interface LayoutConfig {
  theme: TuiButtonProps['theme']
  variant: TuiButtonProps['variant']
}

const layoutMap: Record<MappedLayout, LayoutConfig> = {
  primary: { theme: 'primary', variant: 'solid' },
  action: { theme: 'secondary', variant: 'outline' },
  danger: { theme: 'danger', variant: 'solid' },
  'text-action': { theme: 'secondary', variant: 'ghost' },
  'text-primary': { theme: 'primary', variant: 'ghost' },
  'text-danger': { theme: 'danger', variant: 'ghost' }
}

const isMappedLayout = (value: string): value is MappedLayout => value in layoutMap

type ForwardedTuiProps = Omit<
  TuiButtonProps,
  | 'children'
  | 'theme'
  | 'variant'
  | 'size'
  | 'fullWidth'
  | 'loading'
  | 'leftIconName'
  | 'rightIconName'
  | 'leftIcon'
  | 'rightIcon'
  | 'iconSize'
  | 'href'
  | 'target'
  | 'rel'
  | 'type'
  | 'disabled'
  | 'onClick'
  | 'className'
  | 'content'
>

export interface FieldsButtonProps extends ForwardedTuiProps {
  size?: TuiButtonProps['size']
  theme?: TuiButtonProps['theme']
  variant?: TuiButtonProps['variant']
  fullWidth?: TuiButtonProps['fullWidth']
  loading?: TuiButtonProps['loading']
  leftIconName?: TuiButtonProps['leftIconName']
  rightIconName?: TuiButtonProps['rightIconName']
  leftIcon?: TuiButtonProps['leftIcon']
  rightIcon?: TuiButtonProps['rightIcon']
  iconSize?: TuiButtonProps['iconSize']
  href?: TuiButtonProps['href']
  target?: TuiButtonProps['target']
  rel?: TuiButtonProps['rel']
  children?: ReactNode
  content?: ReactNode
  layout?: string
  type?: string
  buttonType?: 'button' | 'submit' | 'reset'
  context?: string
  className?: string
  style?: CSSProperties
  name?: string
  disabled?: boolean
  isDisabled?: boolean
  onClick?: (event: MouseEvent<HTMLButtonElement | HTMLAnchorElement>) => void
  onPress?: () => void
  testId?: string
  'data-testid'?: string
  'data-test-id'?: string
  'aria-label'?: string
  contentVisuallyHidden?: boolean
  changeTag?: 'button' | 'span'
  data?: unknown
  wrapper?: unknown
  visibility?: unknown
  itemType?: unknown
  afterInitialization?: unknown
  element?: unknown
  condition?: unknown
  portalContainer?: unknown
  onChange?: unknown
}

const Button = forwardRef<HTMLButtonElement | HTMLAnchorElement | HTMLSpanElement, FieldsButtonProps>(
  (props: FieldsButtonProps, ref) => {
  const {
    size,
    fullWidth,
    loading,
    leftIconName,
    rightIconName,
    leftIcon,
    rightIcon,
    iconSize,
    href,
    target,
    rel,
    children,
    content,
    layout,
    type,
    buttonType = 'button',
    testId,
    'data-testid': dataTestId,
    'data-test-id': dataTestIdDashed,
    'aria-label': ariaLabelProp,
    context: _context,
    data: _data,
    wrapper: _wrapper,
    visibility: _visibility,
    itemType: _itemType,
    afterInitialization: _afterInitialization,
    element: _element,
    condition: _condition,
    portalContainer: _portalContainer,
    onChange: _onChange,
    theme,
    variant,
    className,
    style,
    name,
    disabled,
    isDisabled,
    onClick,
    onPress,
    contentVisuallyHidden,
    changeTag,
    ...tuiProps
  } = props

  const hasWarnedSpan = useRef(false)
  const hasWarnedMissingLabel = useRef(false)
  const hasWarnedOnChange = useRef(false)

  useEffect(() => {
    if (!hasWarnedOnChange.current && isDev() && props.onChange !== undefined) {
      console.warn(
        '[Fields Button] `onChange` prop is not supported on Button and will be ignored. ' +
        'Use `onClick` for click handling.'
      )
      hasWarnedOnChange.current = true
    }
  }, [])

  const resolvedLayout = String(layout || type || 'action')
  const resolvedTestId = testId ?? dataTestId ?? dataTestIdDashed

  if (!isMappedLayout(resolvedLayout)) {
    return <LegacyButton ref={ref} {...props} testId={resolvedTestId} />
  }

  const mapped = layoutMap[resolvedLayout]
  const label: ReactNode = content ?? children
  const stringLabel = typeof label === 'string' ? label : undefined
  const computedAriaLabel = contentVisuallyHidden ? stringLabel : undefined
  const ariaLabel = ariaLabelProp ?? computedAriaLabel
  const renderedContent = contentVisuallyHidden ? null : label
  const resolvedDisabled = Boolean(disabled || isDisabled)
  const rawTheme = theme ?? mapped.theme
  const resolvedTheme = rawTheme === 'destructive' ? 'danger' : rawTheme
  const resolvedVariant = variant ?? mapped.variant
  const resolvedSize = size ?? 'md'
  const resolvedLoading = Boolean(loading)

  const handleClick = (event: MouseEvent<HTMLButtonElement | HTMLAnchorElement>) => {
    onClick?.(event)
    onPress?.()
    triggerEvent('buttonPressed', {
      name: name ?? false,
      props,
      event
    })
  }

  if (
    !hasWarnedMissingLabel.current &&
    isDev() &&
    renderedContent == null &&
    !ariaLabel
  ) {
    hasWarnedMissingLabel.current = true
    console.warn(
      '[Fields Button] Button has no visible label and no aria-label. Provide `content`, `children`, or an accessible label.'
    )
  }

  if (changeTag === 'span') {
    if (!hasWarnedSpan.current && isDev()) {
      hasWarnedSpan.current = true
      console.warn(
        '[Fields Button] `changeTag=\"span\"` is supported for backward compatibility but discouraged. Prefer semantic <button> or <a> usage.'
      )
    }

    /**
     * @fragile This span branch manually replicates TUI Button's class contract.
     * If TUI changes its class naming (tui-button, is-size-*, is-theme-*, is-style-*),
     * this branch must be updated to match. There is no automated check for drift.
     * Consider removing changeTag="span" support when legacy callers are migrated.
     */
    const spanClasses = [
      'tui-button',
      `is-size-${resolvedSize}`,
      `is-theme-${resolvedTheme}`,
      resolvedVariant !== 'solid' ? `is-style-${resolvedVariant}` : '',
      fullWidth ? 'is-width-full' : '',
      resolvedDisabled || resolvedLoading ? 'is-disabled' : '',
      className ?? ''
    ]
      .filter(Boolean)
      .join(' ')

    return (
      <span
        ref={ref as Ref<HTMLSpanElement>}
        {...tuiProps}
        className={spanClasses}
        style={style}
        data-testid={resolvedTestId}
        data-test-id={resolvedTestId}
        data-name={name}
        data-loading={resolvedLoading || undefined}
        role="button"
        tabIndex={resolvedDisabled || resolvedLoading ? -1 : 0}
        aria-disabled={resolvedDisabled || resolvedLoading || undefined}
        aria-busy={resolvedLoading || undefined}
        {...(ariaLabel ? { 'aria-label': ariaLabel } : {})}
        onClick={event => {
          if (resolvedDisabled || resolvedLoading) return
          handleClick(event as unknown as MouseEvent<HTMLButtonElement | HTMLAnchorElement>)
        }}
        onKeyDown={event => {
          if (resolvedDisabled || resolvedLoading) return
          if (event.key === 'Enter' || event.key === ' ') {
            event.preventDefault()
            ;(event.currentTarget as HTMLSpanElement).click()
          }
        }}
      >
        {renderedContent}
      </span>
    )
  }

  return (
    <TuiButton
      {...tuiProps}
      ref={ref as Ref<HTMLButtonElement | HTMLAnchorElement>}
      theme={resolvedTheme}
      variant={resolvedVariant}
      size={resolvedSize}
      fullWidth={fullWidth}
      loading={resolvedLoading}
      leftIconName={leftIconName}
      rightIconName={rightIconName}
      leftIcon={leftIcon}
      rightIcon={rightIcon}
      iconSize={iconSize}
      href={href}
      target={target}
      rel={rel}
      type={buttonType}
      disabled={resolvedDisabled}
      onClick={handleClick as TuiButtonProps['onClick']}
      className={className}
      style={style}
      data-testid={resolvedTestId}
      data-test-id={resolvedTestId}
      data-name={name}
      {...(ariaLabel ? { 'aria-label': ariaLabel } : {})}
    >
      {renderedContent}
    </TuiButton>
  )
}
)

Button.displayName = 'Button'

export default Button

import {
  useRef,
  useEffect,
  useState,
  lazy,
  Suspense,
  forwardRef
} from 'react'

import { useTextField } from 'react-aria'
import { Field, TextInput as TuiTextInput } from '@tangible/ui'
import type { SizeStandard, TextInputType } from '@tangible/ui'

import Description from '../../base/field/Description'
import Label from '../../base/field/Label'
import { useInputMask, matchesMask } from '../../../utils/use-input-mask'

const DynamicEditor = lazy(() => import('../../dynamic/editor/DynamicEditor'))

/**
 * Text field with three routing paths:
 * 1. dynamic → ProseMirror-based DynamicEditor (lazy-loaded)
 * 2. inputMask (no dynamic) → TUI TextInput + useInputMask hook
 * 3. plain → TUI TextInput with optional prefix/suffix
 *
 * @see https://react-spectrum.adobe.com/react-aria/useTextField.html
 */

export interface FieldsTextProps {
  dynamic?: unknown
  inputMask?: string
  prefix?: string
  suffix?: string
  value?: string
  onChange?: (value: string) => void
  name?: string
  placeholder?: string
  readOnly?: boolean
  isDisabled?: boolean
  isRequired?: boolean
  isInvalid?: boolean
  error?: boolean
  label?: string
  labelVisuallyHidden?: boolean
  description?: string
  descriptionVisuallyHidden?: boolean
  className?: string
  inputClassName?: string
  size?: SizeStandard
  type?: TextInputType
}

/**
 * Dynamic path sub-component — rendered only when the `dynamic` prop is set.
 * Isolated here so `useTextField` (react-aria) is only called in this path.
 */
const DynamicTextField = (props: FieldsTextProps) => {
  const [value, setValue] = useState(props.value ?? '')
  const ref = useRef<HTMLInputElement | null>(null)
  const mountedRef = useRef(false)

  const {
    labelProps,
    inputProps,
    descriptionProps,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } = useTextField(props as any, ref as any)

  useEffect(() => {
    if (!mountedRef.current) {
      mountedRef.current = true
      return
    }
    if (props.onChange) props.onChange(value)
  }, [value])

  return (
    <div className="tf-text tf-text-dynamic">
      {props.label &&
        <Label labelProps={labelProps} parent={props}>
          {props.label}
        </Label>}
      <Suspense fallback={null}>
        <DynamicEditor
          value={value}
          onChange={setValue}
          dynamic={props.dynamic}
          name={props.name}
          placeholder={props.placeholder}
          readOnly={props.readOnly}
          prefix={props.prefix}
          suffix={props.suffix}
          singleLine={true}
          inputProps={inputProps}
        />
      </Suspense>
      {props.description &&
        <Description descriptionProps={descriptionProps} parent={props}>
          {props.description}
        </Description>}
    </div>
  )
}

const TextField = forwardRef<HTMLInputElement, FieldsTextProps>((props, ref) => {
  const {
    dynamic,
    inputMask,
    prefix,
    suffix,
  } = props

  const hasDynamic = Boolean(dynamic)

  const [value, setValue] = useState(props.value ?? '')
  const inputMaskRef = useRef<HTMLInputElement | null>(null)
  const mountedRef = useRef(false)

  useInputMask(inputMaskRef, !hasDynamic ? inputMask : null)

  useEffect(() => {
    if (!mountedRef.current) {
      mountedRef.current = true
      return
    }
    if (props.onChange) props.onChange(value)
  }, [value])

  /**
   * Dynamic path — delegate to DynamicTextField which calls useTextField.
   * Note: ref is not forwarded to the ProseMirror editor.
   */
  if (hasDynamic) {
    return <DynamicTextField {...props} />
  }

  // Validate initial mask value
  const getInitialMaskValue = () => {
    if (!inputMask || !value) return value
    const stripped = stripAffixes(value, prefix, suffix)
    return matchesMask(stripped, inputMask) ? value : ''
  }

  /**
   * Native path — TUI TextInput (with optional input mask, prefix, suffix)
   */
  return (
    <div className="tf-text tf-text-tui">
      <Field
        className={props.className}
        required={Boolean(props.isRequired)}
        disabled={Boolean(props.isDisabled || props.readOnly)}
        error={Boolean(props.isInvalid || props.error)}
      >
        {props.label &&
          <Field.Label hidden={Boolean(props.labelVisuallyHidden)}>
            {props.label}
          </Field.Label>}
        <Field.Control>
          <TuiTextInput
            ref={node => {
              if (typeof ref === 'function') ref(node)
              else if (ref) ref.current = node
              // TUI TextInput forwards its ref directly to the <input> element —
              // no querySelector needed.
              if (inputMask && node) {
                inputMaskRef.current = node
              }
            }}
            inputClassName={`tui-input-reset ${props.inputClassName ?? ''}`.trim()}
            size={props.size}
            type={props.type ?? 'text'}
            placeholder={props.placeholder}
            readOnly={props.readOnly}
            value={inputMask ? getInitialMaskValue() : value}
            onChange={event => setValue(event.target.value)}
            name={props.name ?? ''}
            prefix={prefix}
            suffix={suffix}
          />
        </Field.Control>
        {props.description &&
          // Field.HelperText has no `hidden` prop — apply `tui-visually-hidden`
          // directly as a className to visually hide while keeping it accessible.
          <Field.HelperText className={props.descriptionVisuallyHidden ? 'tui-visually-hidden' : undefined}>
            {props.description}
          </Field.HelperText>}
      </Field>
    </div>
  )
})

/**
 * Strip prefix/suffix from a stored value for mask validation.
 */
function stripAffixes(value: string, prefix?: string, suffix?: string): string {
  let result = value
  if (prefix && result.startsWith(prefix)) {
    result = result.slice(prefix.length)
  }
  if (suffix && result.endsWith(suffix)) {
    result = result.slice(0, result.length - suffix.length)
  }
  return result
}

export default TextField

